count :: Eq a => a -> [a] -> Int
count i = sum . map (fromEnum . (==) i)

matchPasswordPolicy :: PasswordPolicy -> String -> Bool
matchPasswordPolicy (PasswordPolicy min_count max_count ch) pwd = countPwd >= min_count && countPwd <= max_count where
  countPwd = count ch pwd

countValidPasswords :: [(PasswordPolicy,String)] -> Int
countValidPasswords = count True . map (uncurry matchPasswordPolicy)

xor :: Bool -> Bool -> Bool
xor a b = (a && not b) || (b && not a)

at :: [a] -> Int -> a
at xs i = xs !! (i - 1)

matchSecondPasswordPolicy :: PasswordPolicy -> String -> Bool
matchSecondPasswordPolicy (PasswordPolicy first second ch) pwd = (pwd `at` first == ch) `xor` (pwd `at` second == ch)

countValidPasswords2 :: [(PasswordPolicy,String)] -> Int
countValidPasswords2 = count True . map (uncurry matchSecondPasswordPolicy)

